export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const neighborCounts = new Map<string, [Cell, number]>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const key = cellKey(neighbor);
      const existing = neighborCounts.get(key);
      neighborCounts.set(key, existing ? [existing[0], existing[1] + 1] : [neighbor, 1]);
    }
  }

  const result: Cell[] = [];
  for (const [key, [cell, count]] of neighborCounts) {
    const isAlive = aliveKeys.has(key);
    if ((isAlive && (count === 2 || count === 3)) || (!isAlive && count === 3)) {
      result.push(cell);
    }
  }
  return result;
}

